+fn local_repair_audit_record(
+    phase: &str,
+    outcome: &str,
+    repair: &LocalRepairResult,
+    reason: Option<String>,
+) -> RecoveryAuditRecord {
+    RecoveryAuditRecord {
+        phase: phase.to_string(),
+        action: "local_repair".to_string(),
+        outcome: outcome.to_string(),
+        reason,
+        applied_actions: local_repair_applied_actions(repair),
